  ('pukao-d0d1b9a2-moex-00117', 'pukao-d0d1b9a2', 'pukao-d0d1b9a2-moex-112-6b16960c', 'sub-pukao-d0d1b9a2-04', NULL, 'essay', '請根據我國目前審計準則，僅針對下列各種獨立情況判斷，說明應簽發之
查核意見，並列示該查核報告之結構是否應包含關鍵查核事項段、繼續經
營有關之重大不確定性段、強調事項段及其他事項段。（20分）
㉑李會計師首次受託查核A公司財務報表，未能參與觀察期初存貨之盤點
工作，然受查公司相關的內部控制非常健全，採用其他查核程序後，取
得期初存貨數量及狀況之適切充分證據。
㉒甲集團的重要子公司由其他會計師查核，集團主辦會計師對該會計師
的專業能力、信譽與獨立性感到滿意，但集團主辦會計師決定採責任區
分之。
㉓C受查公司負債大於資產，會計師推斷使受查者繼續經營之能力存在重
大不確定性，惟C公司已於財務報表適當揭露。
㉔會計師查核D公司年度財務報表之際，發現公司之鉅額不動產之交易價
格未考量該項不動產已有他項權利設定，逕參考估價報告之金額作為
最後簽約成交價格依據。會計師經向管理階層查詢，遲遲未獲得回覆，
亦無相關適切充分之證據。', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:01+00:00", "source_pdf_sha1": "af6af81c720a", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "413", "s": "1108", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "審計學概要", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": "二", "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "會計"}'::jsonb, NULL),
